    required this.startedAt,
    this.finishedAt,
    this.errorMessage,
    this.errorStackTrace,
    this.dedupKey,
    this.parentPipelineRunId,
    this.parentStepId,
    required this.templateVersion,
    required this.totalCostCents,
    required this.totalTokens,
    required this.dryRun,
  });
