      map['trigger_event_type'] = Variable<String>(triggerEventType);
    }
    if (!nullToAbsent || triggerPayloadJson != null) {
      map['trigger_payload_json'] = Variable<String>(triggerPayloadJson);
    }
    map['started_at'] = Variable<DateTime>(startedAt);
