      map['error_stack_trace'] = Variable<String>(errorStackTrace);
    }
    if (!nullToAbsent || dedupKey != null) {
      map['dedup_key'] = Variable<String>(dedupKey);
    }
    if (!nullToAbsent || parentPipelineRunId != null) {
      map['parent_pipeline_run_id'] = Variable<String>(parentPipelineRunId);
    }
    if (!nullToAbsent || parentStepId != null) {
      map['parent_step_id'] = Variable<String>(parentStepId);
    }
    map['template_version'] = Variable<int>(templateVersion);
    map['total_cost_cents'] = Variable<int>(totalCostCents);
